import { useState } from "react";
import Api from "../api/Api";
import axios from "axios";

const locations = [
  "Hostel 1",
  "Hostel 2",
  "Hostel 3",
  "Hostel 4",
  "Hostel 5",
  "Hostel 6",
  "Hostel 7",
  "Hostel 8",
  "Hostel 9",
  "Hostel 10",
  "Hostel 11",
  "Hostel 12",

  "Faculty Colony",
  "Staff Colony",
  "Teacher Colony",
  "Boys Colony",
  "Girls Colony",

  "Computer Science Department",
  "Mechanical Department",
  "Civil Department",
  "Electrical Department",
  "MBA Department",
  "MCA Department",
  "Library",
  "Auditorium",
  "Admin Block",
];

export default function CreatePickupRequest() {
  const [search, setSearch] = useState("");
  const [selectedLocation, setSelectedLocation] = useState("");
  const [priority, setPriority] = useState("Medium");
  const [showDropdown, setShowDropdown] = useState(false);

  const filteredLocations = locations.filter((item) =>
    item.toLowerCase().includes(search.toLowerCase())
  );

 const handleSubmit = async () => {
  try {
    if (!selectedLocation) {
      alert("Please select location");
      return;
    }

    const payload = {
      location: selectedLocation,
      priority: priority,
    };

    const response = await axios.post(
     Api.create_Emg_Req,
      payload
    );

    alert(response.data.message);

    setSearch("");
    setSelectedLocation("");
    setPriority("Medium");

  } catch (error) {
    console.error(error);

    alert(
      error.response?.data?.message ||
      "Failed to create request"
    );
  }
};

  return (
    <div className="min-h-screen bg-[#edf0e9] flex justify-center p-4">
      <div className="w-full max-w-sm">

        {/* Header */}

        <div className="mb-6">
          <p className="text-xs tracking-widest text-gray-500 font-semibold">
            FLEET MANAGEMENT
          </p>

          <h1 className="text-4xl font-bold text-green-900">
            Create Pickup Request
          </h1>
        </div>

        {/* Location Card */}

        <div className="bg-white rounded-2xl border p-5 mb-5 shadow-sm">

          <div className="flex justify-between items-center mb-4">
            <h3 className="font-bold text-lg">
              📍 Location
            </h3>

            <button className="text-sm text-green-700 font-semibold">
              Use Current
            </button>
          </div>

          <div className="relative">

            <input
              type="text"
              placeholder="Search pickup address..."
              value={search}
              onChange={(e) => {
                setSearch(e.target.value);
                setShowDropdown(true);
              }}
              className="w-full border rounded-xl px-4 py-3 outline-none"
            />

            {showDropdown && (
              <div className="absolute top-14 w-full bg-white border rounded-xl shadow-lg max-h-60 overflow-y-auto z-50">

                {filteredLocations.length > 0 ? (
                  filteredLocations.map((loc) => (
                    <div
                      key={loc}
                      onClick={() => {
                        setSelectedLocation(loc);
                        setSearch(loc);
                        setShowDropdown(false);
                      }}
                      className="px-4 py-3 hover:bg-green-100 cursor-pointer"
                    >
                      {loc}
                    </div>
                  ))
                ) : (
                  <div className="p-3 text-gray-500">
                    No Location Found
                  </div>
                )}

              </div>
            )}

          </div>

          {selectedLocation && (
            <div className="mt-3 text-green-700 font-semibold">
              Selected : {selectedLocation}
            </div>
          )}
        </div>

        {/* Priority */}

        <div className="bg-white rounded-2xl border p-5 mb-5">

          <h3 className="font-bold text-lg mb-4">
            Priority Level
          </h3>

          <div className="grid grid-cols-3 gap-3">

            <button
              onClick={() => setPriority("Low")}
              className={`py-3 rounded-full border font-medium
              ${
                priority === "Low"
                  ? "bg-green-800 text-white"
                  : ""
              }`}
            >
              Low
            </button>

            <button
              onClick={() => setPriority("Medium")}
              className={`py-3 rounded-full border font-medium
              ${
                priority === "Medium"
                  ? "bg-green-800 text-white"
                  : ""
              }`}
            >
              Medium
            </button>

            <button
              onClick={() => setPriority("High")}
              className={`py-3 rounded-full border font-medium
              ${
                priority === "High"
                  ? "bg-green-800 text-white"
                  : ""
              }`}
            >
              High
            </button>

          </div>
        </div>

        {/* Submit Button */}

        <button
          onClick={handleSubmit}
          className="w-full bg-green-800 text-white py-4 rounded-2xl text-lg font-bold shadow-lg"
        >
          ➤ Submit & Notify Driver
        </button>

      </div>
    </div>
  );
}
